import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def pkg_map(projects):
    result = {}
    for p in projects:
        name = p['path'].split('/')[-2]
        pkgs = {}
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                pkgs[pkg['id']] = pkg['resolvedVersion']
        result[name] = pkgs
    return result

b = pkg_map(baseline['projects'])
a = pkg_map(after['projects'])

print('=== Changes ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg)
        av = ap.get(pkg)
        if bv != av:
            changes = True
            print(f'  {proj}: {pkg} {bv} -> {av}')
if not changes:
    print('  (none)')

print()
print('=== Unchanged ===')
for proj in sorted(a.keys()):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    unchanged = [pkg for pkg in sorted(ap.keys()) if bp.get(pkg) == ap.get(pkg)]
    if unchanged:
        print(f'  {proj}: {', '.join(f\"{p}={ap[p]}\" for p in unchanged)}')
"

